class Solution:
    def isBoomerang(self, points):
        (x1, y1), (x2, y2), (x3, y3) = points[0], points[1], points[2]
        if (x1, y1) == (x2, y2) or (x1, y1) == (x3, y3) or (x2, y2) == (x3, y3):
            return False
        if x2 == x1 and x3 == x1:
            return False
        if x2 != x1 and x3 != x1:
            return (y2 - y1) * (x3 - x1) != (y3 - y1) * (x2 - x1)
        return True

